#include<bits/stdc++.h>#include<ext/pb_ds/assoc_container.hpp>#include<ext/pb_ds/tree_policy.hpp>using namespace std;using namespace __gnu_pbds; #define ll long long#define nl "\n"#define FASTER ios_base::sync_with_stdio(0); cin.tie(0); cout.tie(0);template <typename T> using ordered_set = tree<T,null_type, less<T>, rb_tree_tag, tree_order_statistics_node_update>; const ll N = 1e5+10;const ll mod = 1e9+7;const ll INF = 1e9+10; void solve(){    ll n;    cin>>n;    string s;    cin>>s;    bool ok = false;    for(int i=0; i<(n/2)-1; i++){        if(s[i]==')'){            ok = true;            break;        }    }    if(ok) cout<<n-2<<nl;    else cout<<-1<<nl;} int main(){    FASTER    ll t;    cin>>t;    while(t--){        solve();    }}                  /*Let, s is the given and my soln is t. So that my soln 't' will be better than the 's'.From 1st cond: s is the prefix of t (the 1st condition isn't so important, thats why there is 'or').2nd cond: let, i the first pos where t[i]!=s[i] and t[i]='(' & s[i]=')'. Let, think about the 2nd cond.If n is the size of bracket seq & also there will be n/2 '(' and n/2 ')', then we can create a subseq of thatcondition. Otherwise, if any brackets is greater than n/2 then it gives -1. Let, the case is: s = (((()()())))                  t = ((((..)()))) - valid soln.                   t = ((((.().)))) - valid From this case, the main factor is after getting first ')' in s then we need two '(' brackets. One for thatposition's replacement & other one for deleting opening brackets for balancing. After that we will get a maxposibble length of RBS subseq which is better than s. The another case is: s = (())()                     t = ((() - invalid                     t = (()() - invalid  So, If there is a ')' before the halfway point in s, then there must be at least 2 '(' brackets after it andthe max len will be n-2.*/